"[{\"AllowMultiple\":false,\"EndLine\":208,\"ReplacementContent\":\"def _section_title(ax, title: str, number: int, y_frac=0.96, lang=\\\"en\\\"):\\n    display_title = _t(title, lang)\\n    \\n    if \\\"pAHI\\\" in display_title:\\n        if lang == \\\"he\\\":\\n            clean_title = display_title.replace(\\\"(pAHI)\\\", \\\"\\\").strip()\\n            lines = [clean_title, \\\"(pAHI)\\\"]\\n        else:\\n            # Move \\\"Index (pAHI)\\\" to the second line\\n            clean_title = display_title.replace(\\\"Index (pAHI)\\\", \\\"\\\").replace(\\\"Index\\\", \\\"\\\").replace(\\\"(pAHI)\\\", \\\"\\\").strip()\\n            lines = [clean_title, \\\"Index (pAHI)\\\"]\\n    else:\\n        lines = [display_title]\\n    \\n    if lang == \\\"he\\\":\\n        line0 = f\\\"{get_display(lines[0])} .{number}\\\"\\n    else:\\n        line0 = f\\\"{number}. {lines[0]}\\\"\\n        \\n    # Fixed x_start ensures all bullets are perfectly vertically aligned\\n    x_start = 0.15\\n        \\n    ax.plot(_x(x_start, lang), y_frac, \\\"o\\\", color=ACCENT, markersize=7,\\n            transform=ax.transAxes, clip_on=False, zorder=6)\\n    \\n    base_x = x_start + 0.025\\n    t1 = ax.text(_x(base_x, lang), y_frac, line0,\\n            fontsize=13, fontweight=\\\"bold\\\", color=TEXT_H,\\n            ha=_ha(\\\"left\\\", lang), va=\\\"center\\\", transform=ax.transAxes)\\n            \\n    if len(lines) > 1:\\n        line1_text = get_display(lines[1]) if lang == \\\"he\\\" else lines[1]\\n        \\n        # Calculate the exact visual center of the first line's bounding box\\n        ax.figure.canvas.draw()\\n        bbox = t1.get_window_extent()\\n        bbox_axes = bbox.transformed(ax.transAxes.inverted())\\n        x_center = (bbox_axes.x0 + bbox_axes.x1) / 2\\n        \\n        # Draw second line perfectly centered under the first line's visual bounding box\\n        # Note: x_center is already an absolute axes coordinate, so no _x() is needed\\n        ax.text(x_center, y_frac - 0.13, line1_text,\\n                fontsize=13, fontweight=\\\"bold\\\", color=TEXT_H,\\n                ha=\\\"center\\\", va=\\\"center\\\", transform=ax.transAxes)\",\"\n<truncated 1850 bytes>"